// Itera sobre os itens recebidos
for (const item of items) {
  // Acessa o campo PHONE da saída do nó Switch
  const phone = item.json.body ? item.json.body.PHONE : null;

  // Verifica se o telefone existe e se começa com '+'
  if (phone && phone.startsWith("+")) {
    // Remove o sinal de "+" e armazena o resultado de volta no campo
    item.json.phone = phone.replace("+", "");
  }
}

// Retorna os itens modificados
return items;

